// Helper — maps a course title to a theme key
export function getKey(title) {
  const lower = title.toLowerCase();
  if (lower.includes("c++"))                                 return "c++";
  if (lower.startsWith("node") || lower.includes("node.js")) return "node";
  if (lower.startsWith("dsa")  || lower.includes("algorithm")) return "dsa";
  if (lower.startsWith("git"))                               return "git";
  if (lower.startsWith("sql")  || lower.includes("database"))  return "sql";
  return lower.split(/[\s–-]/)[0];
}

